INSERT OR REPLACE INTO meeting_copy (meeting_id, lang, event_description, history_description) VALUES (17, 'da', 'Blue Prince er et mystisk puslespil om jagten på et hemmeligt 46. værelse i herregodset Mount Holly.

Godsets rum omarrangeres ved hvert forsøg, og du må observere, lære og planlægge for at finde vej dybere ind. Et meditativt spil om logik, mønstre og et mysterium, der langsomt åbner sig.', 'Et mystisk puslespil, hvor du udforsker de proceduralt genererede rum i herregodset Mount Holly på jagt efter et hemmeligt 46. værelse.');
INSERT OR REPLACE INTO meeting_copy (meeting_id, lang, event_description, history_description) VALUES (17, 'en', 'Blue Prince is a mysterious puzzle game where you explore the procedurally arranged rooms of Mount Holly manor, searching for a hidden 46th room.

Each attempt reshuffles the manor, and you must observe, learn and plan to find your way deeper. A meditative game about logic, patterns, and the slow uncovering of a larger secret.', 'A mysterious puzzle game where you explore the procedurally arranged rooms of Mount Holly manor, searching for a hidden 46th room.');

-- Meeting 18: Dispatch
INSERT OR REPLACE INTO games (id, steam_appid, title, header_image, store_url, gog_url, gog_id, genres, platforms, price, playtime_hours, hltb_url, description_da, description_en) VALUES (18, '2592160', 'Dispatch', 'https://cdn.akamai.steamstatic.com/steam/apps/2592160/header.jpg', 'https://store.steampowered.com/app/2592160/Dispatch/', NULL, NULL, 'Narrative, Comedy', 'Windows', NULL, 10, 'https://howlongtobeat.com/game/160618', NULL, NULL);
